          recommended_ticket_update: { ticket_id: ticket.id, stage: "plan_review", approved_plan: true, activate: true },
        }
      }
      return {
        ...base,
        next_allowed_stages: ["implementation"],
        required_artifacts: ["planning"],
        next_action_kind: "ticket_update",
        next_action_tool: "ticket_update",
        delegate_to_agent: "implementer",
        required_owner: "team-leader",
        recommended_action: "Move the ticket into implementation, then delegate the write-capable implementation lane.",
        recommended_ticket_update: { ticket_id: ticket.id, stage: "implementation", activate: true },
      }
    case "implementation": {
      const implementationBlocker = await validateImplementationArtifactEvidence(ticket)
      if (implementationBlocker) {
        return {
          ...base,
          next_allowed_stages: ["implementation"],
          required_artifacts: ["implementation"],
          next_action_kind: "write_artifact",
          next_action_tool: "artifact_write",
          delegate_to_agent: "implementer",
          required_owner: "team-leader",
          canonical_artifact_path: defaultArtifactPath(ticket.id, "implementation", "implementation"),
          artifact_stage: "implementation",
          artifact_kind: "implementation",
          recommended_action: "Stay in implementation. Produce and register the implementation artifact with real execution evidence before review.",
          current_state_blocker: implementationBlocker,
        }
      }
      return {
        ...base,
        next_allowed_stages: ["review"],
        required_artifacts: ["implementation"],
        next_action_kind: "ticket_update",
        next_action_tool: "ticket_update",
        delegate_to_agent: "reviewer-code",
        required_owner: "team-leader",
        recommended_action: "Move the ticket into review once the implementation artifact is current.",
        recommended_ticket_update: { ticket_id: ticket.id, stage: "review", activate: true },
      }
    }
    case "review":
      if (!hasReviewArtifact(ticket)) {
        return {
          ...base,
          next_allowed_stages: ["review"],
          required_artifacts: ["review"],
          next_action_kind: "write_artifact",
          next_action_tool: "artifact_write",
          delegate_to_agent: "reviewer-code",
          required_owner: "team-leader",
          canonical_artifact_path: defaultArtifactPath(ticket.id, "review", "review"),
          artifact_stage: "review",
          artifact_kind: "review",
          recommended_action: "Keep the ticket in review until at least one current review artifact exists.",
          current_state_blocker: "Review artifact missing.",
        }
      }
      return {
        ...base,
        next_allowed_stages: ["qa"],
        required_artifacts: ["review"],
        next_action_kind: "ticket_update",
        next_action_tool: "ticket_update",
        delegate_to_agent: "tester-qa",
        required_owner: "team-leader",
        recommended_action: "Move the ticket into QA after review approval is registered.",
        recommended_ticket_update: { ticket_id: ticket.id, stage: "qa", activate: true },
      }
    case "qa": {
      const qaBlocker = await validateQaArtifactEvidence(ticket)
      if (qaBlocker) {
        return {
          ...base,
          next_allowed_stages: ["qa"],
          required_artifacts: ["qa"],
          next_action_kind: "write_artifact",
          next_action_tool: "artifact_write",
          delegate_to_agent: "tester-qa",
          required_owner: "team-leader",
          canonical_artifact_path: defaultArtifactPath(ticket.id, "qa", "qa"),
          artifact_stage: "qa",
          artifact_kind: "qa",
          recommended_action: "Keep the ticket in QA until the QA artifact includes real command output and passes size checks.",
          current_state_blocker: qaBlocker,
        }
      }
      return {
        ...base,
        next_allowed_stages: ["smoke-test"],
        required_artifacts: ["qa"],
        next_action_kind: "ticket_update",
        next_action_tool: "ticket_update",
        delegate_to_agent: "tester-qa",
        required_owner: "team-leader",
        recommended_action: "Advance to smoke-test, then use the smoke_test tool. Do not write smoke-test artifacts through artifact_write or artifact_register.",
        recommended_ticket_update: { ticket_id: ticket.id, stage: "smoke-test", activate: true },
      }
    }
    case "smoke-test": {
      const smokeBlocker = await validateSmokeTestArtifactEvidence(ticket)
      if (smokeBlocker) {
        return {
          ...base,
          next_allowed_stages: ["smoke-test"],
          required_artifacts: ["smoke-test"],
          next_action_kind: "run_tool",
          next_action_tool: "smoke_test",
          delegate_to_agent: "tester-qa",
          required_owner: "team-leader",
          canonical_artifact_path: defaultArtifactPath(ticket.id, "smoke-test", "smoke-test"),
          artifact_stage: "smoke-test",
          artifact_kind: "smoke-test",
          recommended_action: "Use the smoke_test tool to produce the current smoke-test artifact. Do not fabricate a PASS artifact through generic artifact tools.",
          current_state_blocker: smokeBlocker,
        }
      }
      return {
        ...base,
        next_allowed_stages: ["closeout"],
        required_artifacts: ["smoke-test"],
        next_action_kind: "ticket_update",
        next_action_tool: "ticket_update",
        delegate_to_agent: null,
        required_owner: "team-leader",
        recommended_action: "Move the ticket into closeout/done now that a passing smoke-test artifact exists.",
        recommended_ticket_update: { ticket_id: ticket.id, stage: "closeout", activate: true },
      }
    }
    case "closeout":
      if (ticket.status === "done" && needsProcessVerification) {
        return {
          ...base,
          next_allowed_stages: [],
          required_artifacts: ["review/backlog-verification or linked follow-up evidence"],
          next_action_kind: "reverify",
          next_action_tool: "ticket_reverify",
          delegate_to_agent: "backlog-verifier",
          required_owner: "team-leader",
          canonical_artifact_path: defaultArtifactPath(ticket.id, "review", "backlog-verification"),
          artifact_stage: "review",
          artifact_kind: "backlog-verification",
          recommended_action: "Ticket is already closed, but historical trust still needs restoration. Use the backlog verifier to produce current evidence, then run ticket_reverify on this closed ticket instead of trying to reclaim it.",
          recommended_ticket_update: null,
        }
      }
      return {
        ...base,
        next_allowed_stages: [],
        required_artifacts: ["smoke-test"],
        next_action_kind: ticket.status === "done" ? "noop" : "ticket_update",
        next_action_tool: ticket.status === "done" ? null : "ticket_update",
        delegate_to_agent: null,
        required_owner: "team-leader",
        recommended_action: ticket.status === "done" ? "Ticket is already closed." : "Finish closeout and mark the ticket done.",
        recommended_ticket_update: ticket.status === "done" ? null : { ticket_id: ticket.id, stage: "closeout", activate: true },
      }
    default:
      return {
        ...base,
        next_allowed_stages: [],
        next_action_kind: "inspect",
        next_action_tool: "ticket_lookup",
        required_owner: "team-leader",
        recommended_action: "Current stage is invalid. Repair the workflow contract before continuing.",
      }
  }
}

export default tool({
  description: "Resolve the active ticket or a requested ticket from tickets/manifest.json.",
  args: {
    ticket_id: tool.schema.string().describe("Optional ticket id to resolve. Defaults to the active ticket.").optional(),
    include_artifact_contents: tool.schema.boolean().describe("Whether to include the latest artifact bodies for the resolved ticket.").optional(),
  },
  async execute(args) {
    const manifest = await loadManifest()
    const workflow = await loadWorkflowState()
    const ticket = getTicket(manifest, args.ticket_id)
    const resolvedWorkflow = args.ticket_id
      ? {
          ...workflow,
          active_ticket: ticket.id,
          stage: ticket.stage,
          status: ticket.status,
          approved_plan: isPlanApprovedForTicket(workflow, ticket.id),
        }
      : workflow
    const latestPlan = latestArtifact(ticket, { stage: "planning" }) || null
    const latestImplementation = latestArtifact(ticket, { stage: "implementation" }) || null
    const latestReview = latestReviewArtifact(ticket) || null
    const latestBacklogVerification = latestArtifact(ticket, { stage: "review", kind: "backlog-verification" }) || null
    const latestQa = latestArtifact(ticket, { stage: "qa" }) || null
    const latestSmokeTest = latestArtifact(ticket, { stage: "smoke-test" }) || null
    const transitionGuidance = await buildTransitionGuidance(ticket, resolvedWorkflow)

    const artifactSummary = {
      current_valid_artifacts: currentArtifacts(ticket),
      historical_artifacts: historicalArtifacts(ticket),
      has_plan: hasArtifact(ticket, { stage: "planning" }),
      has_implementation: hasArtifact(ticket, { stage: "implementation" }),
      has_review: hasReviewArtifact(ticket),
      has_qa: hasArtifact(ticket, { stage: "qa" }),
      has_smoke_test: hasArtifact(ticket, { stage: "smoke-test" }),
      latest_plan: latestPlan,
      latest_implementation: latestImplementation,
      latest_review: latestReview,
      latest_backlog_verification: latestBacklogVerification,
      latest_qa: latestQa,
      latest_smoke_test: latestSmokeTest,
    }

--- ticket_update ---
import { tool } from "@opencode-ai/plugin"
import {
  describeAllowedStatusesForStage,
  getTicket,
  hasArtifact,
  hasPendingRepairFollowOn,
  hasReviewArtifact,
  isPlanApprovedForTicket,
  loadManifest,
  loadWorkflowState,
  markTicketDone,
  nextRepairFollowOnStage,
  repairFollowOnBlockingReason,
  resolveRequestedTicketProgress,
  saveWorkflowBundle,
  setPlanApprovedForTicket,
  syncWorkflowSelection,
  ticketsNeedingProcessVerification,
  validateLifecycleStageStatus,
  validateImplementationArtifactEvidence,
  validateQaArtifactEvidence,
  validateSmokeTestArtifactEvidence,
} from "../lib/workflow"

export default tool({
  description: "Update ticket stage, status, summary, and active ticket state.",
  args: {
    ticket_id: tool.schema.string().describe("Ticket id to update."),
    stage: tool.schema.string().describe("Optional new stage value.").optional(),
    status: tool.schema.string().describe("Optional new status value.").optional(),
    summary: tool.schema.string().describe("Optional replacement summary.").optional(),
    activate: tool.schema.boolean().describe("Whether to set this ticket as the active ticket.").optional(),
    approved_plan: tool.schema.boolean().describe("Whether this ticket's plan is approved in workflow-state.").optional(),
    pending_process_verification: tool.schema.boolean().describe("Whether post-migration backlog verification is still pending.").optional(),
  },
  async execute(args) {
    const manifest = await loadManifest()
    const workflow = await loadWorkflowState()
    if (hasPendingRepairFollowOn(workflow)) {
      const repairBlocker = repairFollowOnBlockingReason(workflow) || (
        nextRepairFollowOnStage(workflow)
          ? `Repair follow-on remains incomplete. Complete \`${nextRepairFollowOnStage(workflow)}\` before resuming normal ticket lifecycle mutations.`
          : "Repair follow-on remains incomplete. Complete the required repair stages before resuming normal ticket lifecycle mutations."
      )
      throw new Error(repairBlocker)
    }
    const ticket = getTicket(manifest, args.ticket_id)
    const wasDone = ticket.status === "done"
    const requested = resolveRequestedTicketProgress(ticket, { stage: args.stage, status: args.status })
    const targetStage = requested.stage
    const targetStatus = requested.status

    const lifecycleBlocker = validateLifecycleStageStatus(targetStage, targetStatus)
    if (lifecycleBlocker) {
      throw new Error(lifecycleBlocker)
    }

    if (wasDone && targetStatus !== "done") {
      throw new Error(`Ticket ${ticket.id} is already done. Use ticket_reopen to resume ownership instead of mutating status directly.`)
    }

    if (typeof args.approved_plan === "boolean" && args.approved_plan && !hasArtifact(ticket, { stage: "planning" })) {
      throw new Error("Cannot approve a plan before a planning artifact exists.")
    }

    if (targetStage === "plan_review") {
      if (!hasArtifact(ticket, { stage: "planning" })) {
        throw new Error("Cannot move to plan_review before a planning artifact exists.")
      }
    }

    if (targetStage === "implementation" && args.approved_plan === true && !isPlanApprovedForTicket(workflow, ticket.id)) {
      throw new Error(`Approve ${ticket.id} while it remains in plan_review first, then move it to implementation in a separate ticket_update call.`)
    }

    if (targetStage === "implementation" && !isPlanApprovedForTicket(workflow, ticket.id)) {
      throw new Error(`Cannot move ${ticket.id} to implementation before its plan is approved in workflow-state.`)
    }

    if (targetStage === "implementation" && ticket.stage !== "plan_review") {
      throw new Error(`Cannot move ${ticket.id} to implementation before it passes through plan_review.`)
    }

    if (targetStage === "review") {
      const implementationBlocker = await validateImplementationArtifactEvidence(ticket)
      if (implementationBlocker) {
        throw new Error(implementationBlocker)
      }
    }

    if (targetStage === "qa" && !hasReviewArtifact(ticket)) {
      throw new Error("Cannot move to qa before at least one review artifact exists.")
    }

    if (targetStage === "smoke-test") {
      const qaBlocker = await validateQaArtifactEvidence(ticket)
      if (qaBlocker) {
        throw new Error(qaBlocker)
      }
    }

    if (targetStage === "closeout") {
      const smokeTestBlocker = await validateSmokeTestArtifactEvidence(ticket)
      if (smokeTestBlocker) {
        throw new Error(smokeTestBlocker)
      }
    }

    ticket.stage = targetStage
    if (targetStatus === "done") {
      markTicketDone(ticket, workflow)
    } else {
      ticket.status = targetStatus
    }
    if (args.summary) ticket.summary = args.summary
    if (args.activate) manifest.active_ticket = ticket.id

    if (typeof args.approved_plan === "boolean") {
      setPlanApprovedForTicket(workflow, ticket.id, args.approved_plan)
    }
    syncWorkflowSelection(workflow, manifest)
    if (typeof args.pending_process_verification === "boolean") {
      if (args.pending_process_verification === false) {
        // Intentionally inspect post-mutation state so the clear operation validates the repo exactly as it would be persisted.
        const unverified = ticketsNeedingProcessVerification(manifest, workflow)
        if (unverified.length > 0) {
          throw new Error(
            `Cannot clear pending_process_verification: ${unverified.length} done ticket(s) still require backlog verification (${unverified.map((t) => t.id).join(", ")}). Run the backlog-verifier flow for the listed tickets, register review/backlog-verification artifacts where needed, then retry.`,
          )
        }
      }
      workflow.pending_process_verification = args.pending_process_verification
    }

    await saveWorkflowBundle({ workflow, manifest })

    return JSON.stringify(
      {
        updated_ticket: ticket,
        transition: {
          stage: targetStage,
          status: targetStatus,
          allowed_statuses_for_stage: describeAllowedStatusesForStage(targetStage),
        },
        active_ticket: manifest.active_ticket,
        workflow,
      },
      null,
      2,
    )
  },
})

--- smoke_test ---
import { tool } from "@opencode-ai/plugin"
import { spawn } from "node:child_process"
import { existsSync } from "node:fs"
import { access, readFile } from "node:fs/promises"
import { join } from "node:path"
import {
  currentArtifacts,
  defaultArtifactPath,
  getTicket,
  latestArtifact,
  loadArtifactRegistry,
  loadManifest,
  loadWorkflowState,
  normalizeRepoPath,
  registerArtifactSnapshot,
  requireBootstrapReady,
  rootPath,
  saveArtifactRegistry,
  saveManifest,
  writeText,
} from "../lib/workflow"

type PackageJson = {
  packageManager?: string
  scripts?: Record<string, string>
}

type CommandSpec = {
  label: string
  argv: string[]
  reason: string
  env_overrides?: Record<string, string>
}

type CommandResult = CommandSpec & {
  exit_code: number
  duration_ms: number
  stdout: string
  stderr: string
}

type PythonRunner = {
  label: string
  argv: string[]
  reason: string
}
type SmokeArgs = {
  ticket_id?: string
  scope?: string
  test_paths?: string[]
  command_override?: string[]
}

const SMOKE_STAGE = "smoke-test"
const SMOKE_KIND = "smoke-test"
const ENV_ASSIGNMENT_PATTERN = /^[A-Za-z_][A-Za-z0-9_]*=.*/
const SMOKE_COMMAND_PATTERNS = [
  /\bpytest\b/i,
  /\bpython(?:3)?\s+-m\s+pytest\b/i,
  /\b(?:uv\s+run\s+)?ruff\s+check\b/i,
  /\bcargo\s+test\b/i,
  /\bgo\s+test\b/i,
  /\b(?:npm|pnpm)\s+run\s+(?:test|check)\b/i,
  /\byarn\s+(?:test|check)\b/i,
  /\bbun\s+run\s+(?:test|check)\b/i,
]

async function exists(path: string): Promise<boolean> {
  try {
    await access(path)
    return true
  } catch {
    return false
  }
}

async function readJson<T>(path: string): Promise<T | undefined> {
  try {
    return JSON.parse(await readFile(path, "utf-8")) as T
  } catch {
    return undefined
  }
}
async function readText(path: string): Promise<string> {
  try {
    return await readFile(path, "utf-8")
  } catch {
    return ""
  }
}
function hasSectionValue(text: string, section: string, key: string): boolean {
  const blockMatch = text.match(new RegExp(`\\[${section.replace(".", "\\.")}\\]([\\s\\S]*?)(?:\\n\\[|$)`, "m"))
  if (!blockMatch) return false
  return new RegExp(`^\\s*${key.replace("-", "\\-")}\\s*=\\s*(?:\\[|\\{)`, "m").test(blockMatch[1] || "")
}
// Mirror bootstrap detection for [tool.pytest.ini_options] so pyproject-only pytest repos are not skipped.
function hasPyprojectPytestConfig(pyprojectText: string): boolean {
  return /\[tool\.pytest\.ini_options\]/m.test(pyprojectText)
}
function hasPyprojectDevExtra(pyprojectText: string): boolean {
  return hasSectionValue(pyprojectText, "project.optional-dependencies", "dev")
}
function hasPyprojectDevDependencyGroup(pyprojectText: string): boolean {
  return hasSectionValue(pyprojectText, "dependency-groups", "dev")
}
function hasPyprojectUvDevDependencies(pyprojectText: string): boolean {
  return /\[tool\.uv(?:\.[^\]]+)?\][\s\S]*?^\s*dev-dependencies\s*=/m.test(pyprojectText) || /\[tool\.uv\.dev-dependencies\]/m.test(pyprojectText)
}
function detectUvRunDependencyArgs(pyprojectText: string): string[] {
  if (hasPyprojectDevExtra(pyprojectText)) return ["--extra", "dev"]
  if (hasPyprojectDevDependencyGroup(pyprojectText)) return ["--group", "dev"]
  if (hasPyprojectUvDevDependencies(pyprojectText)) return ["--all-extras"]
  return []
}

function choosePackageManager(root: string, packageJson: PackageJson | undefined): "npm" | "pnpm" | "yarn" | "bun" {
  const declared = packageJson?.packageManager?.toLowerCase() || ""
  if (declared.startsWith("pnpm")) return "pnpm"
  if (declared.startsWith("yarn")) return "yarn"
  if (declared.startsWith("bun")) return "bun"
  if (declared.startsWith("npm")) return "npm"
  if (existsSync(join(root, "pnpm-lock.yaml"))) return "pnpm"
  if (existsSync(join(root, "yarn.lock"))) return "yarn"
  if (existsSync(join(root, "bun.lock")) || existsSync(join(root, "bun.lockb"))) return "bun"
  return "npm"
}

function packageCommand(manager: "npm" | "pnpm" | "yarn" | "bun", script: string): string[] {
  if (manager === "yarn") return ["yarn", script]
  if (manager === "bun") return ["bun", "run", script]
  if (manager === "pnpm") return ["pnpm", "run", script]
  return ["npm", "run", script]
}

async function detectNodeCommands(root: string): Promise<CommandSpec[]> {
  const packagePath = join(root, "package.json")
  if (!(await exists(packagePath))) {
    return []
  }

  const packageJson = await readJson<PackageJson>(packagePath)
  const scripts = packageJson?.scripts || {}
  const manager = choosePackageManager(root, packageJson)

  for (const explicit of ["smoke-test", "smoke_test"]) {
    if (scripts[explicit]) {
      return [
        {
          label: `package script ${explicit}`,
          argv: packageCommand(manager, explicit),
          reason: "Project-defined smoke-test override",
        },
      ]
    }
  }

  const commands: CommandSpec[] = []
  for (const script of ["check", "build", "test"]) {
    if (!scripts[script]) continue
    commands.push({
      label: `package script ${script}`,
      argv: packageCommand(manager, script),
      reason: `Detected ${script} script in package.json`,
    })
  }
  return commands
}

function extractBacktickedCommands(text: string): string[] {
  return Array.from(text.matchAll(/`([^`\n]+)`/g), (match) => match[1]?.trim() || "").filter(Boolean)
}

function looksLikeSmokeCommand(command: string): boolean {
  return SMOKE_COMMAND_PATTERNS.some((pattern) => pattern.test(command))
}

function inferAcceptanceSmokeCommands(ticket: { acceptance?: unknown }): CommandSpec[] {
  const commands: CommandSpec[] = []
  const seen = new Set<string>()
  const acceptanceItems = Array.isArray(ticket.acceptance) ? ticket.acceptance : []

  for (const item of acceptanceItems) {
    if (typeof item !== "string") continue
    for (const candidate of extractBacktickedCommands(item)) {
      if (!looksLikeSmokeCommand(candidate)) continue
      const normalized = candidate.trim().toLowerCase()
      if (seen.has(normalized)) continue
      const parsed = parseCommandOverride([candidate])
      commands.push({
        ...parsed,
        label: `acceptance command ${commands.length + 1}`,
        reason: "Ticket acceptance criteria define an explicit smoke-test command.",
      })
      seen.add(normalized)
    }
  }

  return commands
}

async function detectPythonRunner(root: string, pyprojectText: string): Promise<PythonRunner> {
  if (await exists(join(root, "uv.lock"))) {
    return {
      label: "uv-managed python",
      argv: ["uv", "run", ...detectUvRunDependencyArgs(pyprojectText), "python"],
      reason: "Detected uv.lock; using repo-managed uv runtime",
    }
  }

  const repoVenvPython = join(root, ".venv", "bin", "python")
  if (await exists(repoVenvPython)) {
    return {
      label: "repo-local python",
      argv: [repoVenvPython],
      reason: "Detected repo-local .venv; using project virtualenv interpreter",
    }
  }

  return {
    label: "system python",
    argv: ["python3"],
    reason: "No repo-managed Python runtime detected; falling back to system python",
  }
}

async function detectPythonCompileCommand(root: string, pyprojectText?: string): Promise<CommandSpec | null> {
  const pythonSignals = ["pyproject.toml", "requirements.txt", "setup.py", "setup.cfg"]
  const hasPythonProject = await Promise.all(pythonSignals.map((name) => exists(join(root, name)))).then((hits) => hits.some(Boolean))
  if (!hasPythonProject) {
    return null
  }
  const resolvedPyprojectText = pyprojectText ?? await readText(join(root, "pyproject.toml"))
  const pythonRunner = await detectPythonRunner(root, resolvedPyprojectText)

  return {
    label: "python compileall",
    argv: [
      ...pythonRunner.argv,
      "-m",
      "compileall",
      "-q",
      "-x",
      "(^|/)(\\.git|\\.opencode|node_modules|dist|build|out|venv|\\.venv|__pycache__)(/|$)",
      ".",
    ],
    reason: `${pythonRunner.reason}; generic Python syntax smoke check`,
  }
}

async function detectPythonCommands(root: string, args: SmokeArgs): Promise<CommandSpec[]> {
  const pythonSignals = ["pyproject.toml", "requirements.txt", "setup.py", "setup.cfg"]
  const hasPythonProject = await Promise.all(pythonSignals.map((name) => exists(join(root, name)))).then((hits) => hits.some(Boolean))
  if (!hasPythonProject) {
    return []
  }
  const pyprojectText = await readText(join(root, "pyproject.toml"))
  const pythonRunner = await detectPythonRunner(root, pyprojectText)
  const compileCommand = await detectPythonCompileCommand(root, pyprojectText)
  const commands: CommandSpec[] = compileCommand ? [compileCommand] : []

  const hasPytestSurface = (await exists(join(root, "tests"))) || (await exists(join(root, "pytest.ini"))) || hasPyprojectPytestConfig(pyprojectText)
  if (hasPytestSurface) {
    const testTargets = Array.isArray(args.test_paths) && args.test_paths.length > 0 ? args.test_paths : []
    commands.push({
      label: "pytest",
      argv: [...pythonRunner.argv, "-m", "pytest", ...testTargets],
      reason: testTargets.length > 0
        ? `${pythonRunner.reason}; running ticket-scoped Python tests`
        : `${pythonRunner.reason}; detected Python test surface`,
    })
  }

  return commands
}

async function detectAcceptanceCommands(root: string, ticket: { acceptance?: unknown }): Promise<CommandSpec[]> {
  const acceptanceCommands = inferAcceptanceSmokeCommands(ticket)
  if (acceptanceCommands.length === 0) {
    return []
  }

  const compileCommand = await detectPythonCompileCommand(root)
  const commands = compileCommand ? [compileCommand, ...acceptanceCommands] : acceptanceCommands
  const seen = new Set<string>()
  return commands.filter((command) => {
    const key = command.argv.join("\u0000")
    if (seen.has(key)) {
      return false
    }
    seen.add(key)
    return true
  })
}

async function detectRustCommands(root: string): Promise<CommandSpec[]> {
  if (!(await exists(join(root, "Cargo.toml")))) {
    return []
